mapper.select:
select tableid as tableId, objectId as objectId, SOURCEID as sourceId, tablename as objectEnglishName, objectname as objectChineseName, updatetime as modDate, case when SECONDARYDATASOURCECH is null then primarydatasourcech else primarydatasourcech || '->' || SECONDARYDATASOURCECH end as dataSourceClassify from (select distinct o.*, case when sourceParVci.CODETEXT is null then '未知' else sourceParVci.CODETEXT end as PRIMARYDATASOURCECH, case when (sourceVci.CODETEXT is null and sourceParVci.CODETEXT is null) then '未知' when (sourceVci.CODETEXT is null and sourceParVci.CODETEXT is not null) then '' else sourceVci.CODETEXT end as SECONDARYDATASOURCECH from (select o.* from (select objectId, SOURCEID, tablename, objectname, tableid, updatetime, SJZYLYLXVALUE from synlte.object where DELETED = 0 and upper(relate_tablename) = 'OBJECTFIELD') o where exists (select 1 from (select sjxjbm from classify_interface_all_date where SJEJFLCODENAME = '0191' or SJYJFLCODENAME = '04') cd where cd.sjxjbm = o.tableid)) o left join v_classify_info sourceVci on upper(sourceVci.codename) = upper(o.SJZYLYLXVALUE) and sourceVci.root = 'GACODE000404' left join v_classify_info sourceParVci on upper(sourceParVci.codeid) = upper(sourceVci.parcodeid))
(upper(objectname) like upper(concat('%',concat(#{searchText},'%'))) or upper(tableName) like upper(concat('%',concat(#{searchText},'%'))) or upper(tableId) like upper(concat('%',concat(#{searchText},'%'))) or upper(sourceId) like upper(concat('%',concat(#{searchText},'%'))) )
order by ${sort} ${sortOrder}

mapper.insert:
merge into STANDARDIZE_OBJECT_RELATION a using (select #{objectId} as objectId from dual) b on ( upper(a.OBJECT_ID) = upper(b.objectId)) when matched then update set ID = #{id}
,OBJECT_NAME = #{objectName,jdbcType=VARCHAR}
,TABLE_ID = #{tableId,jdbcType=VARCHAR}
,PARENT_ID = #{parentId,jdbcType=VARCHAR}
,CREATE_TIME = sysdate when not matched then insert VALUES(#{id},#{objectId},#{objectName},#{tableId},#{parentId},sysdate,sysdate)

insert into STANDARDIZE_OBJECTFIELD_REL(SET_ID,ID,RECNO,COLUMN_NAME,GADSJ_FIELDID,DICTIONARY_REF_ID,DICTIONARY_REF, DICTIONARY_CONTENT_ID,DICTIONARY_CONTENT,PARENT_ID,PARENT_COLUMN_NAME,CREATE_TIME,FIELDCHINESENAME) select * from(
select #{item.setId},#{item.id},#{item.recno,jdbcType=INTEGER},#{item.columnName,jdbcType=VARCHAR}, #{item.gadsjFieldId,jdbcType=VARCHAR},#{item.dictionaryRefId,jdbcType=VARCHAR}, #{item.dictionaryRef,jdbcType=VARCHAR},#{item.dictionaryContentId,jdbcType=VARCHAR},#{item.dictionaryContent,jdbcType=VARCHAR} ,#{item.parentId},#{item.parentColumnName,jdbcType=VARCHAR}, sysdate,#{item.fieldChineseName,jdbcType=VARCHAR} from dual
)

mapper.update:
update STANDARDIZE_OBJECTFIELD_REL set DICTIONARY_REF_ID=#{dictionaryRefId,jdbcType=VARCHAR},
DICTIONARY_REF=#{dictionaryRef,jdbcType=VARCHAR},DICTIONARY_CONTENT_ID=#{dictionaryContentId,jdbcType=VARCHAR},
DICTIONARY_CONTENT=#{dictionaryContent,jdbcType=VARCHAR},PARENT_ID=#{parentId},UPDATE_TIME=sysdate where column_name=#{columnName} and gadsj_fieldId=#{gadsjFieldId}

mapper.select:
select OBJECTID, RECNO, FIELDID, FIELDNAME, FIELDCHINEENAME, FIELDDESCRIBE, FIELDTYPE, FIELDLEN, DEFAULTVALUE, ISINDEX,NEEDVALUE, ISCONTORL, COLUMNNAME, MEMO, TABLEINDEX, ISQUERY, COLUMNNAME_STATE, MD5_INDEX, ISPRIVATE, STANDARD_RECNO, PK_RECNO, PARTITION_RECNO, CLUST_RECNO, ORA_SHOW, NEEDV, FIELDTYPES, NEEDVALUES, ODPS_PATTITION, PRO_TYPE, FIELDSOURCETYPE,DETERMINERID,ZDMGDFLDM,GADSJ_FIELDID from synlte.OBJECTFIELD
and objectId = #{objectId}
order by RECNO
objectId = #{objectId}
and (upper(COLUMNNAME) like upper(concat('%',concat(#{searchText},'%')))) or (upper(FIELDCHINEENAME) like upper(concat('%',concat(#{searchText},'%'))))
